const graphBtn = document.querySelector('#show-graph');

graphBtn.addEventListener('click', async () => {
  console.log('User clicked graph! Downloading library now...');

  try {
    // The code halts here while the browser downloads heavyChart.js over the network
    const chartModule = await import('./heavyChart.js');

    // Once downloaded, we can use the functions inside it!
    chartModule.renderGraph();
  } catch (err) {
    console.error('Failed to load chart module', err);
  }
});

